class Solution:
    def reorganizeString(self, s: str) -> str:
        cnt = Counter(s)
        maxHeap = [(-v, c) for c, v in cnt.items()]
        heapify(maxHeap)
        ans = []
        prev = None
        while maxHeap:
            v, c = heappop(maxHeap)
            ans.append(c)
            if prev:
                heappush(maxHeap, prev)
                prev = None
            if v + 1 < 0:
                prev = (v + 1, c)
        return "".join(ans) if len(ans) == len(s) else ""

