class Solution {
public:
    string reorganizeString(string s) {
        int cnt[26]={}; for(char c:s) cnt[c-'a']++;
        int mx=*max_element(cnt,cnt+26);
        if(mx>(int)s.size()+1)/2) return "";
        string ans(s.size(),' ');
        int i=0;
        for(int c=0;c<26;c++) while(cnt[c]-- > 0){
            ans[i]=c+'a'; i+=2; if(i>=(int)s.size()) i=1;
        }
        return ans;
    }
};

