char* reorganizeString(char* s) {
    int cnt[26]={0}; for(;*s;s++) cnt[*s-'a']++;
    int n=strlen(s), mx=0; for(int i=0;i<26;i++) if(cnt[i]>mx) mx=cnt[i];
    if(mx>(n+1)/2) return strdup("");
    char* ans=malloc(n+1); int i=0;
    for(int c=0;c<26;c++) while(cnt[c]-->0){ ans[i]=c+'a'; i+=2; if(i>=n) i=1; }
    ans[n]=0; return ans;
}
